import React, { useState } from "react";
import { Outlet, NavLink, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const NAV = [
  { to: "/dashboard", icon: "⬡", label: "Dashboard" },
  { to: "/students", icon: "◈", label: "Students" },
  { to: "/students/add", icon: "⊕", label: "Add Student" },
];

export default function Layout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [collapsed, setCollapsed] = useState(false);

  const handleLogout = () => { logout(); navigate("/login"); };

  return (
    <div style={{ display: "flex", minHeight: "100vh" }}>
      {/* Sidebar */}
      <aside style={{
        width: collapsed ? 64 : 220,
        background: "var(--bg2)",
        borderRight: "1px solid var(--border)",
        display: "flex",
        flexDirection: "column",
        transition: "width 0.25s",
        position: "fixed",
        top: 0, left: 0, bottom: 0,
        zIndex: 100,
        overflow: "hidden",
      }}>
        {/* Logo */}
        <div style={{
          padding: "20px 16px",
          borderBottom: "1px solid var(--border)",
          display: "flex",
          alignItems: "center",
          gap: 12,
          minHeight: 64,
        }}>
          <div style={{
            width: 32, height: 32,
            background: "var(--accent)",
            borderRadius: 4,
            display: "flex", alignItems: "center", justifyContent: "center",
            fontFamily: "var(--mono)", fontWeight: 700, fontSize: 14,
            flexShrink: 0,
          }}>FS</div>
          {!collapsed && (
            <span style={{ fontFamily: "var(--mono)", fontWeight: 700, fontSize: 16, letterSpacing: 2 }}>
              FAILSAFE
            </span>
          )}
        </div>

        {/* Nav */}
        <nav style={{ flex: 1, padding: "16px 0" }}>
          {NAV.map(({ to, icon, label }) => (
            <NavLink
              key={to}
              to={to}
              style={({ isActive }) => ({
                display: "flex",
                alignItems: "center",
                gap: 12,
                padding: "10px 16px",
                color: isActive ? "var(--accent)" : "var(--text2)",
                textDecoration: "none",
                fontFamily: "var(--mono)",
                fontSize: 12,
                fontWeight: 700,
                letterSpacing: "0.05em",
                textTransform: "uppercase",
                background: isActive ? "rgba(255,60,95,0.08)" : "transparent",
                borderLeft: isActive ? "2px solid var(--accent)" : "2px solid transparent",
                transition: "all 0.15s",
              })}
            >
              <span style={{ fontSize: 18, flexShrink: 0 }}>{icon}</span>
              {!collapsed && label}
            </NavLink>
          ))}
        </nav>

        {/* User + collapse */}
        <div style={{ borderTop: "1px solid var(--border)", padding: 12 }}>
          {!collapsed && (
            <div style={{ padding: "8px 4px", marginBottom: 8 }}>
              <div style={{ fontWeight: 600, fontSize: 13, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                {user?.name}
              </div>
              <div style={{ color: "var(--text3)", fontSize: 11, fontFamily: "var(--mono)", textTransform: "uppercase" }}>
                {user?.role}
              </div>
            </div>
          )}
          <div style={{ display: "flex", gap: 6 }}>
            <button
              onClick={handleLogout}
              className="btn btn-ghost btn-sm"
              style={{ flex: 1, justifyContent: "center" }}
            >
              {collapsed ? "↩" : "Logout"}
            </button>
            <button
              onClick={() => setCollapsed(c => !c)}
              className="btn btn-ghost btn-sm"
              style={{ padding: "6px 10px" }}
            >
              {collapsed ? "→" : "←"}
            </button>
          </div>
        </div>
      </aside>

      {/* Main */}
      <main style={{
        marginLeft: collapsed ? 64 : 220,
        flex: 1,
        padding: "32px 36px",
        transition: "margin-left 0.25s",
        minHeight: "100vh",
        background: "var(--bg)",
      }}>
        <Outlet />
      </main>
    </div>
  );
}
